
import Sidebar from "../components/sidebar";
import Header from "../components/header";
import MainTitle from "../components/mainTitle";
import "./warehouse.css";

export default function Warehouse() {
  const [assets, setAssets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchAssets = async () => {
      try {
        const res = await fetch("/api/warehouse");
        
        if (res.status === 401) {
          window.location.href = "/login";
          return;
        }

        if (!res.ok) throw new Error("فشل تحميل البيانات");

        const data = await res.json();
        setAssets(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchAssets();
  }, []);

  return (
    <div className="container">
      {/* Header */}
      <Header />

      {/* Main Layout */}
      <div className="main-layout">
        {/* Sidebar */}
        <Sidebar />

        <main className="main-content">
          {/* Main Title */}
          <MainTitle />
          <div className="add-button">
            <button>
              <img src="/icon/plus.svg" alt="plus" />
              اضافة عهدة
            </button>
          </div>
          <div className="container-warehouse">
            <div className="title-table">قائمة العهد في المخزن</div>
            <div className="toolbar">
              <div className="search-box">
                <input type="text" placeholder="بحث..." />
                <span className="search-icon">
                  <img src="/icon/search.svg" alt="search" />
                </span>
              </div>
              <div className="filter-box">
                <select name="filter" id="filter" defaultValue="">
                  <option value="">جميع العمليات</option>
                  <option value="serialNumber">الرقم التسلسلي</option>
                </select>
                <span className="filter-icon">
                  <img src="/icon/ix_filter.svg" alt="filter" />
                </span>
              </div>
            </div>
            <div className="table-container">
              <table>
                <thead>
                  <tr>
                    <th>الاسم</th>
                    <th>الحالة</th>
                    <th>السعر</th>
                    <th>الرقم التسلسلي</th>
                    <th>نوع الأصل</th>
                    <th>الغرفة</th>
                    <th>الفئة</th>
                    <th>الوحدة</th>
                  </tr>
                </thead>
                <tbody id="tbody">
                  <tr>
                    <td>جهاز حاسوب Dell XPS 15</td>
                    <td>جيد</td>
                    <td>1000</td>
                    <td>123456789</td>
                    <td>حاسوب</td>
                    <td>غرفة 101</td>
                    <td>إلكترونيات</td>
                    <td>وحدة 1</td>
                  </tr>
                  <tr>
                    <td>جهاز حاسوب Dell XPS 15</td>
                    <td>جيد</td>
                    <td>1000</td>
                    <td>123456789</td>
                    <td>حاسوب</td>
                    <td>غرفة 101</td>
                    <td>إلكترونيات</td>
                    <td>وحدة 1</td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}
